import{_ as a,a as i}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as o,o as e,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const w=JSON.parse('{"title":"Limity uploadu dla użytkowników","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Safety/user-rate-limits.md","filePath":"pl-PL/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),l={name:"pl-PL/Safety/user-rate-limits.md"};function p(r,t,y,s,u,c){return e(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="limity-uploadu-dla-uzytkownikow" tabindex="-1">Limity uploadu dla użytkowników <a class="header-anchor" href="#limity-uploadu-dla-uzytkownikow" aria-label="Permalink to &quot;Limity uploadu dla użytkowników&quot;">​</a></h1><p>Limity uploadu kontrolują, jak często zwykli użytkownicy lub odwiedzający mogą przesyłać pliki ze strony głównej. Pomaga to zapobiegać nadużyciom publicznych stron uploadu.</p><p>Ta funkcja dotyczy tylko uploadów ze strony głównej. Uploady administratora i uploady przez API Tokens nie są ograniczane tymi limitami.</p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz panel administracyjny, a następnie przejdź do:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+a+'" alt="Ustawienia limitów użytkownika" loading="lazy"></p><h2 id="właczanie-limitow" tabindex="-1">Włączanie limitów <a class="header-anchor" href="#właczanie-limitow" aria-label="Permalink to &quot;Włączanie limitów&quot;">​</a></h2><p>Po włączeniu <code>Enable Rate Limits</code> ImgBed śledzi ostatnie uploady według adresu IP osoby przesyłającej.</p><p>Wartości domyślne:</p><table tabindex="0"><thead><tr><th>Ustawienie</th><th>Domyślnie</th><th>Opis</th></tr></thead><tbody><tr><td>Okno wykrywania</td><td>1,5 godziny</td><td>Jak daleko wstecz liczone są rekordy uploadu.</td></tr><tr><td>Maksymalna liczba plików</td><td>20</td><td>Maksymalna liczba plików w oknie wykrywania.</td></tr><tr><td>Limit pojedynczego pliku</td><td>20 MB</td><td>Maksymalny rozmiar jednego pliku.</td></tr><tr><td>Limit łącznego uploadu</td><td>200 MB</td><td>Maksymalny łączny rozmiar uploadu w oknie wykrywania.</td></tr></tbody></table><p>Na przykład przy oknie 1,5 godziny, 20 plikach, 20 MB na plik i 200 MB łącznie, uploady z tego samego IP zostaną zablokowane po przekroczeniu dowolnego ustawionego limitu.</p><h2 id="wykluczanie-typow-plikow" tabindex="-1">Wykluczanie typów plików <a class="header-anchor" href="#wykluczanie-typow-plikow" aria-label="Permalink to &quot;Wykluczanie typów plików&quot;">​</a></h2><p><code>Excluded upload file types</code> blokuje zwykłym użytkownikom lub odwiedzającym przesyłanie wybranych kategorii plików.</p><p>Dostępne kategorie:</p><table tabindex="0"><thead><tr><th>Typ</th><th>Opis</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif i podobne pliki obrazów</td></tr><tr><td>Videos</td><td>mp4, webm, mov i podobne pliki wideo</td></tr><tr><td>Audio</td><td>mp3, flac, wav i podobne pliki audio</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx i podobne dokumenty</td></tr><tr><td>Other</td><td>Pliki spoza powyższych kategorii, np. zip, rar, exe, apk</td></tr></tbody></table><p>Domyślnie typ niezaznaczony jest dozwolony.</p><p>Kliknięcie typu podświetla go, co oznacza blokadę tego typu.</p><p>Jeśli <code>Other</code> jest zaznaczone, odwiedzający przesyłający zip lub rar zostaną zablokowani i zobaczą informację, że ten typ pliku nie jest obsługiwany.</p><h2 id="komunikaty-blokady" tabindex="-1">Komunikaty blokady <a class="header-anchor" href="#komunikaty-blokady" aria-label="Permalink to &quot;Komunikaty blokady&quot;">​</a></h2><p>Po uruchomieniu limitu użytkownik widzi odpowiedni komunikat:</p><p><img src="'+i+'" alt="Komunikat zbyt częstego uploadu" loading="lazy"></p><table tabindex="0"><thead><tr><th>Sytuacja</th><th>Znaczenie komunikatu</th></tr></thead><tbody><tr><td>Pojedynczy plik za duży</td><td>Plik jest za duży i powinien zostać skompresowany przed uploadem.</td></tr><tr><td>Typ pliku zablokowany</td><td>Ten typ pliku nie jest obsługiwany. Usuń go i spróbuj ponownie.</td></tr><tr><td>Uploady zbyt częste</td><td>Ostatnie uploady są zbyt częste; pokazany jest czas ponownej próby.</td></tr><tr><td>Łączny rozmiar za duży</td><td>Ostatni łączny rozmiar uploadu jest za duży; pokazany jest czas ponownej próby.</td></tr></tbody></table><h2 id="kiedy-właczyc" tabindex="-1">Kiedy włączyć <a class="header-anchor" href="#kiedy-właczyc" aria-label="Permalink to &quot;Kiedy włączyć&quot;">​</a></h2><p>Włącz limity użytkownika, jeśli strona uploadu jest publicznie dostępna.</p><p>Typowe powody:</p><ul><li>obawiasz się skryptowych uploadów masowych.</li><li>chcesz ograniczyć duże uploady od odwiedzających.</li><li>chcesz, aby zwykli użytkownicy przesyłali tylko obrazy, a nie archiwa lub instalatory.</li><li>chcesz zachować publiczny upload, ale kontrolować zużycie zasobów.</li></ul><p>Jeśli strona jest tylko dla Ciebie albo uploadować mogą tylko administratorzy, możesz zostawić tę funkcję wyłączoną.</p>',28)])])}const m=o(l,[["render",p]]);export{w as __pageData,m as default};
